    mercuryToString(stack, Precision, t4, o[1], 1024);
    mercuryToString(stack, Precision, t5, o[2], 1024);
    printf ("%s pow %s = %s\n", o[0], o[1], o[2]);





    mercuryToString(stack, Precision, t4, txt, 1024);
    printf("correct answer : %s\n", txt);

    mercuryToString(stack, Precision, t, o[0], 1024);
    mercuryToString(stack, Precision, t2, o[1], 1024);
    mercuryToString(stack, Precision, t4, o[2], 1024);

    printf ("%s log %s = %s\n", o[0], o[1], o[2]);



    clock_t start, end;
    if (false) {
        start = clock();
        mercuryLogSlow(stack, Precision, t, t2, t3);
        end = clock();

        printf("mercuryLogSlow : %lf\n", (end - start) / (double) CLOCKS_PER_SEC);

        mercuryToString(stack, Precision, t, o[0], 1024);
        mercuryToString(stack, Precision, t2, o[1], 1024);
        mercuryToString(stack, Precision, t3, o[2], 1024);
        printf("%s log %s = %s\n", o[0], o[1], o[2]);

        mercuryPow(stack, Precision, t2, t3, t4);

        mercuryToString(stack, Precision, t2, o[0], 1024);
        mercuryToString(stack, Precision, t3, o[1], 1024);
        mercuryToString(stack, Precision, t4, o[2], 1024);
        printf("%s pow %s = %s\n", o[0], o[1], o[2]);
    }
    start = clock();
    mercuryLog(stack, Precision, t, t2, t3);
    end = clock();

    printf("mercuryLog : %lf\n", (end-start) / (double) CLOCKS_PER_SEC);

    mercuryToString(stack, Precision, t, o[0], 1024);
    mercuryToString(stack, Precision, t2, o[1], 1024);
    mercuryToString(stack, Precision, t3, o[2], 1024);
    printf ("%s log %s = %s\n", o[0], o[1], o[2]);

    mercuryPow(stack, Precision, t2, t3, t4);

    mercuryToString(stack, Precision, t2, o[0], 1024);
    mercuryToString(stack, Precision, t3, o[1], 1024);
    mercuryToString(stack, Precision, t4, o[2], 1024);
    printf ("%s pow %s = %s\n", o[0], o[1], o[2]);

    mercuryStackFree(stack, stack_size);

    printf("________%ld________\n", ((ulong *)stack)[0]);
